SELECT product_id AS productId, product_category AS productCategory, target_type AS targetType, product_name AS productName, base_interest_rate AS baseInterestRate, max_interest_rate AS maxInterestRate, min_duration_months AS minDurationMonths, max_duration_months AS maxDurationMonths, min_amount AS minAmount, max_amount AS maxAmount, description, is_active AS isActive, created_at AS createdAt, updated_at AS updatedAt FROM `bank`.`financial_product` WHERE is_active = TRUE
AND product_category = #{category}
ORDER BY product_id DESC LIMIT #{limit} OFFSET #{offset}

mapper.update:
